sFinishCode	; save finish codeosf1:	lda 3 UserFinishProc	snz 3 3			; is there a user finish procedure?	 jmp boot		; no	lda 0 @.OsFinishCode	; yes. call it with the finish code as arg	jsr 0 3	 1	jmp osf1		; check for more of themboot:	dir			; There is no return from here	lda 3 lvEtherBoot	; EtherBoot static	lda 3 0 3		; de-reference	sta 3 lvEtherBoot	; save that addressEBRetry:lda 0 BFN		; boot file number	mkminusone 1 1		; return on fail = true	jsr @lvEtherBoot	; Call EtherBoot	 2			; 2 args	dsz retryCnt		; failed.	 jmp EBRetry		; try again	lda 0 BFN		; this file is a loser	snz 0 0			; is it the basic diagnostic?	 jmp .			; yes.  something is very wrong.	sub 0 0			; no.  try the basic diagnostic	sta 0 BFN	lda 0 C5		; try 4 more times	sta 0 retryCnt	jmp EBRetryUserFinishProc:	.blk 1.OsFinishCode:	OsFinishCodelvEtherBoot:	EtherBootretryCnt:	5		; # of times to retry an EtherBootC5:		5BFN:		10		; default is net exec	.end